def gen(rng, size):
    n = max(2, min(size, 50))
    rows = []
    for r in range(n):
        chars = []
        for c in range(n):
            if r == 0 and c == 0:
                chars.append('E')
            elif r == n - 1 and c == n - 1:
                chars.append('S')
            elif rng.random() < 0.15:
                chars.append('X')
            else:
                chars.append(str(rng.randint(1, 9)))
        rows.append(''.join(chars))
    return [rows]

