class Solution:
    def pathsWithMaxScore(self, board):
        MOD = 10**9 + 7
        n = len(board)
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(1000000)
        # best[r][c] = (maxscore, count) to go from (r,c) to E at (0,0)
        @lru_cache(maxsize=None)
        def solve(r, c):
            if r == 0 and c == 0:
                return (0, 1)
            ch = board[r][c]
            if ch == 'X':
                return (-1, 0)
            best = -1
            ways = 0
            for dr, dc in ((-1, 0), (0, -1), (-1, -1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < n and 0 <= nc < n:
                    s, w = solve(nr, nc)
                    if s < 0:
                        continue
                    if s > best:
                        best = s
                        ways = w
                    elif s == best:
                        ways = (ways + w) % MOD
            if best < 0:
                return (-1, 0)
            add = 0 if ch in 'ES' else int(ch)
            return (best + add, ways)
        s, w = solve(n - 1, n - 1)
        if s < 0 or w == 0:
            return [0, 0]
        return [s, w % MOD]

