class Solution:
    def pathsWithMaxScore(self, board):
        MOD = 10**9 + 7
        n = len(board)
        NEG = -1
        score = [[NEG] * n for _ in range(n)]
        cnt = [[0] * n for _ in range(n)]
        score[0][0] = 0
        cnt[0][0] = 1
        for r in range(n):
            for c in range(n):
                if r == 0 and c == 0:
                    continue
                ch = board[r][c]
                if ch == 'X':
                    continue
                best = NEG
                ways = 0
                for dr, dc in ((-1, 0), (0, -1), (-1, -1)):
                    pr, pc = r + dr, c + dc
                    if 0 <= pr < n and 0 <= pc < n and score[pr][pc] != NEG:
                        s = score[pr][pc]
                        if s > best:
                            best = s
                            ways = cnt[pr][pc]
                        elif s == best:
                            ways = (ways + cnt[pr][pc]) % MOD
                if best == NEG:
                    continue
                add = 0 if ch in 'ES' else int(ch)
                score[r][c] = best + add
                cnt[r][c] = ways
        if score[n - 1][n - 1] == NEG or cnt[n - 1][n - 1] == 0:
            return [0, 0]
        return [score[n - 1][n - 1], cnt[n - 1][n - 1] % MOD]

