var pathsWithMaxScore = function(board) {
    const MOD = 1000000007n;
    const n = board.length;
    const NEG = -1;
    const score = Array.from({length: n}, () => new Array(n).fill(NEG));
    const cnt = Array.from({length: n}, () => new Array(n).fill(0n));
    score[0][0] = 0;
    cnt[0][0] = 1n;
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < n; c++) {
            if (r === 0 && c === 0) continue;
            const ch = board[r][c];
            if (ch === 'X') continue;
            let best = NEG;
            let ways = 0n;
            const moves = [[-1, 0], [0, -1], [-1, -1]];
            for (const [dr, dc] of moves) {
                const pr = r + dr, pc = c + dc;
                if (pr >= 0 && pr < n && pc >= 0 && pc < n && score[pr][pc] !== NEG) {
                    const s = score[pr][pc];
                    if (s > best) { best = s; ways = cnt[pr][pc]; }
                    else if (s === best) { ways = (ways + cnt[pr][pc]) % MOD; }
                }
            }
            if (best === NEG) continue;
            const add = (ch === 'E' || ch === 'S') ? 0 : parseInt(ch, 10);
            score[r][c] = best + add;
            cnt[r][c] = ways;
        }
    }
    if (score[n - 1][n - 1] === NEG || cnt[n - 1][n - 1] === 0n) return [0, 0];
    return [score[n - 1][n - 1], Number(cnt[n - 1][n - 1] % MOD)];
};
